package net.momcorp.persons.domain.service;

import net.momcorp.persons.domain.model.Email;
import net.momcorp.persons.domain.model.Person;
import net.momcorp.persons.domain.model.PersonId;
import net.momcorp.persons.domain.port.in.FindPersonUseCase;
import net.momcorp.persons.domain.port.in.RegisterPersonUseCase;
import net.momcorp.persons.domain.port.out.PersonRepository;

import java.time.LocalDate;
import java.util.List;
import java.util.UUID;

/** Domain service — implements both driving ports; pure Java, zero Spring. */
public class PersonDomainService implements RegisterPersonUseCase, FindPersonUseCase {

    private final PersonRepository repository;

    public PersonDomainService(PersonRepository repository) {
        this.repository = repository;
    }

    @Override
    public Person register(String firstName, String lastName, String email, LocalDate dateOfBirth) {
        var emailVo = new Email(email);
        if (repository.existsByEmail(emailVo.value())) {
            throw new IllegalStateException("E-mail already registered: " + email);
        }
        return repository.save(Person.create(firstName, lastName, emailVo, dateOfBirth));
    }

    @Override
    public Person findById(UUID id) {
        return repository.findById(PersonId.of(id));
    }

    @Override
    public List<Person> findAll() {
        return repository.findAll();
    }
}

