package net.momcorp.persons.adapter.in.web;

import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import net.momcorp.persons.domain.port.in.FindPersonUseCase;
import net.momcorp.persons.domain.port.in.RegisterPersonUseCase;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.util.UriComponentsBuilder;

import java.util.List;
import java.util.UUID;

@RestController
@RequestMapping("/api/v1/persons")
@Tag(name = "Persons", description = "Manage person records")
class PersonController {

    private final RegisterPersonUseCase register;
    private final FindPersonUseCase find;

    PersonController(RegisterPersonUseCase register, FindPersonUseCase find) {
        this.register = register;
        this.find = find;
    }

    @Operation(summary = "Register a new person")
    @PostMapping
    ResponseEntity<PersonResponse> register(@Valid @RequestBody PersonRequest req,
                                            UriComponentsBuilder ucb) {
        var person = register.register(req.firstName(), req.lastName(), req.email(), req.dateOfBirth());
        var location = ucb.path("/api/v1/persons/{id}").buildAndExpand(person.id().value()).toUri();
        return ResponseEntity.created(location).body(PersonResponse.from(person));
    }

    @Operation(summary = "Find a person by ID")
    @GetMapping("/{id}")
    ResponseEntity<PersonResponse> findById(@PathVariable UUID id) {
        return ResponseEntity.ok(PersonResponse.from(find.findById(id)));
    }

    @Operation(summary = "List all persons")
    @GetMapping
    ResponseEntity<List<PersonResponse>> findAll() {
        return ResponseEntity.ok(find.findAll().stream().map(PersonResponse::from).toList());
    }
}

